import express, { IRouter, RequestHandler } from "express"
import fs from "fs"
import path from "path"
import type { InlineConfig, ViteDevServer } from "vite"

import { BundlerOptions } from "../types"
import { getViteConfig } from "../utils/config"

const router = express.Router()

function findTemplateFilePath(
  reqPath: string,
  root: string
): string | undefined {
  if (reqPath.endsWith(".html")) {
    const pathToTest = path.join(root, reqPath)
    if (fs.existsSync(pathToTest)) {
      return pathToTest
    }
  }

  const basePath = reqPath.slice(0, reqPath.lastIndexOf("/"))
  const dirs = basePath.split("/")

  while (dirs.length > 0) {
    const pathToTest = path.join(root, ...dirs, "index.html")
    if (fs.existsSync(pathToTest)) {
      return pathToTest
    }
    dirs.pop()
  }

  return undefined
}

async function injectViteMiddleware(
  router: express.Router,
  middleware: RequestHandler
) {
  router.use((req, res, next) => {
    req.path.endsWith(".html") ? next() : middleware(req, res, next)
  })
}

async function injectHtmlMiddleware(
  router: express.Router,
  server: ViteDevServer
) {
  router.use(async (req, res, next) => {
    if (req.method !== "GET") {
      return next()
    }

    const templateFilePath = findTemplateFilePath(req.path, server.config.root)
    if (!templateFilePath) {
      return next()
    }

    const template = fs.readFileSync(templateFilePath, "utf8")
    const html = await server.transformIndexHtml(
      templateFilePath,
      template,
      req.originalUrl
    )

    res.send(html)
  })
}

export async function develop(options: BundlerOptions): Promise<IRouter> {
  const vite = await import("vite")

  try {
    const viteConfig = await getViteConfig(options)

    const developConfig: InlineConfig = {
      mode: "development",
      logLevel: "error",
      appType: "spa",
      server: {
        middlewareMode: true,
      },
    }

    const mergedConfig = vite.mergeConfig(viteConfig, developConfig)
    const server = await vite.createServer(mergedConfig)

    await injectViteMiddleware(router, server.middlewares)
    await injectHtmlMiddleware(router, server)
  } catch (error) {
    console.error(error)
    throw new Error(
      "Failed to start admin development server. See error above."
    )
  }

  return router
}

onHeaders(res, function onResponseHeaders () {
  // determine if request is filtered
  if (!filter(req, res)) {
    nocompress('filtered')
    return
  }

  // determine if the entity should be transformed
  if (!shouldTransform(req, res)) {
    nocompress('no transform')
    return
  }

  // vary
  vary(res, 'Accept-Encoding')

  // content-length below threshold
  if (Number(res.getHeader('Content-Length')) < threshold || length < threshold) {
    nocompress('size below threshold')
    return
  }

  var encoding = res.getHeader('Content-Encoding') || 'identity'

  // already encoded
  if (encoding !== 'identity') {
    nocompress('already encoded')
    return
  }

  // head
  if (req.method === 'HEAD') {
    nocompress('HEAD request')
    return
  }

  // compression method
  var negotiator = new Negotiator(req)
  var method = negotiator.encoding(SUPPORTED_ENCODING, PREFERRED_ENCODING)

  // if no method is found, use the default encoding
  if (!req.headers['accept-encoding'] && encodingSupported.indexOf(enforceEncoding) !== -1) {
    method = enforceEncoding
  }

  // negotiation failed
  if (!method || method === 'identity') {
    nocompress('not acceptable')
    return
  }

  // compression stream
  debug('%s compression', method)
  stream = method === 'gzip'
    ? zlib.createGzip(opts)
    : method === 'br'
      ? zlib.createBrotliCompress(optsBrotli)
      : zlib.createDeflate(opts)

  // add buffered listeners to stream
  addListeners(stream, stream.on, listeners)

  // header fields
  res.setHeader('Content-Encoding', method)
  res.removeHeader('Content-Length')

  // compression
  stream.on('data', function onStreamData (chunk) {
    if (_write.call(res, chunk) === false) {
      stream.pause()
    }
  })

  stream.on('end', function onStreamEnd () {
    _end.call(res)
  })

  _on.call(res, 'drain', function onResponseDrain () {
    stream.resume()
  })
})

var merge = require('utils-merge');

function SessionManager(options, serializeUser) {
  if (typeof options == 'function') {
    serializeUser = options;
    options = undefined;
  }
  options = options || {};

  this._key = options.key || 'passport';
  this._serializeUser = serializeUser;
}

SessionManager.prototype.logIn = function(req, user, options, cb) {
  if (typeof options == 'function') {
    cb = options;
    options = {};
  }
  options = options || {};

  if (!req.session) { return cb(new Error('Login sessions require session support. Did you forget to use `express-session` middleware?')); }

  var self = this;
  var prevSession = req.session;

  // regenerate the session, which is good practice to help
  // guard against forms of session fixation
  req.session.regenerate(function(err) {
    if (err) {
      return cb(err);
    }

    self._serializeUser(user, req, function(err, obj) {
      if (err) {
        return cb(err);
      }
      if (options.keepSessionInfo) {
        merge(req.session, prevSession);
      }
      if (!req.session[self._key]) {
        req.session[self._key] = {};
      }
      // store user information in session, typically a user id
      req.session[self._key].user = obj;
      // save the session before redirection to ensure page
      // load does not happen before session is saved
      req.session.save(function(err) {
        if (err) {
          return cb(err);
        }
        cb();
      });
    });
  });
}

SessionManager.prototype.logOut = function(req, options, cb) {
  if (typeof options == 'function') {
    cb = options;
    options = {};
  }
  options = options || {};

  if (!req.session) { return cb(new Error('Login sessions require session support. Did you forget to use `express-session` middleware?')); }

  var self = this;

  // clear the user from the session object and save.
  // this will ensure that re-using the old session id
  // does not have a logged in user
  if (req.session[this._key]) {
    delete req.session[this._key].user;
  }
  var prevSession = req.session;

  req.session.save(function(err) {
    if (err) {
      return cb(err)
    }

    // regenerate the session, which is good practice to help
    // guard against forms of session fixation
    req.session.regenerate(function(err) {
      if (err) {
        return cb(err);
      }
      if (options.keepSessionInfo) {
        merge(req.session, prevSession);
      }
      cb();
    });
  });
}


module.exports = SessionManager;
